// Modern Gooseneck Kitchen Faucet — BREP / replicad showcase.
//
// Single fused solid (printable): every junction overlaps its neighbour by
// >=0.8 units. The signature is the smooth tall arching gooseneck spout — an
// exact toroidal bend (a true swept surface) rising from a cylindrical body,
// with a single lever handle and an aerator tip. Brushed-metal body + a
// colored lever accent.
//
// Coordinate frame: Z up. The deck plate sits at z=0; the spout arches over
// in the +X direction and the aerator points back down.
const { BREP } = api;

// ---------------------------------------------------------------------------
// Tunables
// ---------------------------------------------------------------------------
const DECK_R = 14;     // escutcheon / base plate radius
const DECK_H = 2.2;    // base plate height
const COLLAR_R = 8.5;  // body cylinder radius
const BODY_H = 30;     // straight body riser height (before the bend)

const TUBE_R = 4.0;    // gooseneck tube radius
const BEND_R = 16;     // gooseneck arch major radius (centerline)

// ---------------------------------------------------------------------------
// 1. Base plate + body riser (the cylindrical column)
// ---------------------------------------------------------------------------
// Wide escutcheon disc on the deck.
const deck = BREP.cylinder(DECK_R, DECK_H);

// Tapered transition from the wide deck up into the slim body.
const flare = BREP.cone(DECK_R - 1.5, COLLAR_R, 4).translate([0, 0, DECK_H - 0.4]);

// Straight body riser. Overlaps the flare top by ~1.
const body = BREP.cylinder(COLLAR_R, BODY_H).translate([0, 0, DECK_H + 3]);

// Top of the straight body in world Z (where the bend begins).
const bendStartZ = DECK_H + 3 + BODY_H; // = 35.2

// ---------------------------------------------------------------------------
// 2. The gooseneck arch — exact toroidal bend (the showpiece smooth surface)
// ---------------------------------------------------------------------------
// A torus lies in the XY plane (axis Z). Rotating it -90 about X stands its
// plane up into XZ, so the tube sweeps in a vertical arc. We keep the
// upper-half arch (a 180 degree bend) that rises, curves over, and brings the
// spout tip back down — the classic gooseneck silhouette.
let arch = BREP.torus(BEND_R, TUBE_R).rotate(-90, [1, 0, 0]);
// Keep only z >= 0 (the top half / arch).
arch = arch.intersect(BREP.box([200, 60, 200]).translate([0, 0, 0]));
// Lift the feet to the body top and shift so the rising foot is on the axis.
arch = arch.translate([BEND_R, 0, bendStartZ - 0.5]);
// Now: rising foot at x=0 (over the body), descending foot at x=2*BEND_R.

const footZ = bendStartZ - 0.5;          // world z of both arch feet (centerline)
const spoutTipX = 2 * BEND_R;            // descending foot x

// ---------------------------------------------------------------------------
// 3. Aerator tip — a short downward nozzle at the descending foot.
// ---------------------------------------------------------------------------
// cylinder base at z=0 by default; build pointing up then flip down so the
// flared lip sits at the bottom. Overlaps the arch foot by ~1.5.
const aeratorBody = BREP.cylinder(TUBE_R + 0.4, 4)
  .translate([0, 0, -4])                 // top at z=0, base at z=-4
  .translate([spoutTipX, 0, footZ + 1.5]);
const aeratorLip = BREP.cone(TUBE_R + 1.4, TUBE_R - 0.2, 2.2)
  .translate([0, 0, -2.2])               // build downward-tapering ring
  .translate([spoutTipX, 0, footZ + 1.5 - 4]);

// ---------------------------------------------------------------------------
// 4. Single lever handle — a slim arm projecting from the body side, with a
//    pivot hub and a paddle tip. This is the colored accent.
// ---------------------------------------------------------------------------
const hubZ = DECK_H + 3 + BODY_H * 0.58;
const TILT = 28 * Math.PI / 180;           // lever rise angle off horizontal

// Pivot hub: a short cylinder whose axis lies along Y, poking out of the body.
// cylinder default axis +Z, base z=0; rotate -90 about X lays it along +Y.
const hub = BREP.cylinder(3.6, 7)
  .rotate(-90, [1, 0, 0])                 // axis -> +Y, body now at y in [0,7]
  .translate([0, COLLAR_R - 2.0, hubZ]);  // bite 2 units into the body wall

// Lever arm + paddle tip — built TOGETHER in a simple local frame (bar lying
// along +Y from y=0, sphere overlapping its far end), then tilted and moved as
// one unit. Building them pre-transform guarantees the weld regardless of how
// the rotation mixes the axes.
const LEVER_LEN = 20;
const HUB_Y = COLLAR_R - 1.5;             // y where the arm leaves the hub
const barLocal = BREP.box([3.6, LEVER_LEN, 3.6])
  .fillet(1.4, { inDirection: [0, 1, 0] })   // round the long edges
  .translate([0, LEVER_LEN / 2, 0]);         // near end at local y=0, centred z
const tipLocal = BREP.sphere(3.2).translate([0, LEVER_LEN - 1.0, 0]); // overlaps bar end
let leverAssembly = BREP.fuseAll([barLocal, tipLocal])
  .rotate(-(28), [1, 0, 0])                  // tilt the free end up
  .translate([0, HUB_Y, hubZ]);
const lever = leverAssembly;
const leverTip = null;

// ---------------------------------------------------------------------------
// 5. Label + fuse.
// ---------------------------------------------------------------------------
const bodyGroup = BREP.label(
  BREP.fuseAll([deck, flare, body, arch, aeratorBody, aeratorLip]),
  'body',
);
const handleGroup = BREP.label(
  BREP.fuseAll([hub, lever]),
  'handle',
);

return BREP.fuseAll([bodyGroup, handleGroup]);

